#include <iostream>
#include <vector>
#include <unordered_map>
#include <sys/socket.h>
#include <netinet/in.h>
#include <unistd.h>
#include <cstring>
#include <thread>
#include <chrono>

struct Player {
    int id;
    float x, y, z;
    float pitch, yaw;
    int health;
    bool isAlive;
};

struct PositionPacket {
    int playerId;
    float x, y, z;
    float pitch, yaw;
    char type;
};

struct ShootPacket {
    int playerId;
    float x, y, z;
    float pitch, yaw;
    char type;
};

class GameServer {
private:
    int serverSocket;
    sockaddr_in serverAddr;
    std::unordered_map<int, Player> players;
    std::vector<char> packetBuffer;
    std::thread listenThread;
    bool running;

public:
    GameServer() : running(false) {
        packetBuffer.resize(1024);
    }

    bool initialize(int port) {
        serverSocket = socket(AF_INET, SOCK_DGRAM, 0);
        if (serverSocket < 0) return false;

        serverAddr.sin_family = AF_INET;
        serverAddr.sin_addr.s_addr = INADDR_ANY;
        serverAddr.sin_port = htons(port);

        if (bind(serverSocket, (sockaddr*)&serverAddr, sizeof(serverAddr)) < 0) {
            return false;
        }

        running = true;
        listenThread = std::thread(&GameServer::listenForPackets, this);
        return true;
    }

    void listenForPackets() {
        while (running) {
            int bytesReceived = recvfrom(serverSocket, packetBuffer.data(), packetBuffer.size(), 0, nullptr, nullptr);
            if (bytesReceived > 0) {
                processPacket(packetBuffer.data(), bytesReceived);
            }
        }
    }

    void processPacket(char* data, int length) {
        if (length < sizeof(char)) return;

        char packetType = data[0];
        if (packetType == 'P') {
            PositionPacket* posPacket = (PositionPacket*)data;
            updatePlayerPosition(posPacket);
        } else if (packetType == 'S') {
            ShootPacket* shootPacket = (ShootPacket*)data;
            processShoot(shootPacket);
        }
    }

    void updatePlayerPosition(PositionPacket* packet) {
        if (players.find(packet->playerId) == players.end()) {
            players[packet->playerId] = {packet->playerId, packet->x, packet->y, packet->z, packet->pitch, packet->yaw, 100, true};
        } else {
            players[packet->playerId].x = packet->x;
            players[packet->y] = packet->y;
            players[packet->z] = packet->z;
            players[packet->pitch] = packet->pitch;
            players[packet->yaw] = packet->yaw;
        }
    }

    void processShoot(ShootPacket* packet) {
        if (players.find(packet->playerId) == players.end() || !players[packet->playerId].isAlive) return;

        // Simple hit detection - just broadcast shoot event
        broadcastShoot(packet);
    }

    void broadcastShoot(ShootPacket* packet) {
        sendto(serverSocket, (char*)packet, sizeof(ShootPacket), 0, nullptr, 0);
    }

    void sendPlayerUpdates() {
        for (auto& pair : players) {
            Player& player = pair.second;
            PositionPacket posPacket = {player.id, player.x, player.y, player.z, player.pitch, player.yaw, 'P'};
            sendto(serverSocket, (char*)&posPacket, sizeof(PositionPacket), 0, nullptr, 0);
        }
    }

    void run() {
        while (running) {
            sendPlayerUpdates();
            std::this_thread::sleep_for(std::chrono::milliseconds(100));
        }
    }

    void stop() {
        running = false;
        if (listenThread.joinable()) listenThread.join();
        close(serverSocket);
    }
};

int main() {
    GameServer server;
    if (!server.initialize(8080)) {
        std::cerr << "Failed to start server" << std::endl;
        return 1;
    }

    server.run();
    return 0;
}